/**
 * Utility functions for disbursement forms
 */
import { GHANA_BANKS } from '@/features/payment-methods/constants';

/**
 * Map bank name to its 3-letter code
 * @param {string} bankName - Name of the bank
 * @returns {string} 3-letter bank code or empty string
 */
export const mapBankNameToCode = (bankName) => {
  if (!bankName) {return '';}
  const normalizedSearch = bankName.toLowerCase().trim();
  const bank = GHANA_BANKS.find(b => 
    b.label.toLowerCase().includes(normalizedSearch) || 
    normalizedSearch.includes(b.label.toLowerCase())
  );
  return bank?.value || '';
};

/**
 * Map display provider name to API provider value
 * @param {string} displayProvider - Display name (e.g., "MTN", "Telecel")
 * @returns {string} API provider value
 */
export const mapProviderToApiValue = (displayProvider) => {
  const mapping = {
    'MTN': 'MTN',
    'Telecel': 'TELECEL', // Changed from 'VODAFONE' to 'TELECEL' for B2C deposits
  };
  return mapping[displayProvider] || displayProvider?.toUpperCase();
};

/**
 * Map display provider name to iVerify operator value
 * @param {string} displayProvider - Display name (e.g., "MTN", "Telecel")
 * @returns {string} iVerify operator value ("mtn" or "vodafone")
 */
export const mapProviderToIVerifyOperator = (displayProvider) => {
  const mapping = {
    'mtn': 'mtn',
    'MTN': 'mtn',
    'Telecel': 'vodafone', // Telecel maps to vodafone in iVerify API
    'TELECEL': 'vodafone',
    'vodafone': 'vodafone',
    'VODAFONE': 'vodafone',
    'AIRTEL-TIGO': 'airteltigo',
    'airtel-tigo': 'airteltigo',
    'AirtelTigo': 'airteltigo',
    'airteltigo': 'airteltigo',
    'AIRTELTIGO': 'airteltigo',
    'airtigo': 'airteltigo',
  };
  return mapping[displayProvider] || 'mtn';
};

/**
 * Get channel code from payment method
 * @param {string} paymentMethod - Payment method name
 * @returns {string} Channel code
 */
export const getChannelFromPaymentMethod = (paymentMethod) => {
  if (paymentMethod === 'Mobile Money' || paymentMethod === 'MOMO') {
    return 'MOBILE_MONEY';
  }
  if (paymentMethod === 'Bank' || paymentMethod === 'BANK') {
    return 'BANK';
  }
  if (paymentMethod === 'Wallet' || paymentMethod === 'WALLET') {
    return 'WALLET';
  }
  return 'MOBILE_MONEY';
};

/**
 * Validate reference number format
 * Pattern: ^[0-9a-zA-Z \w+]{1,20}$
 * Allows: alphanumeric, space, underscore, plus sign, 1-20 characters
 * @param {string} reference - Reference to validate
 * @returns {boolean} True if valid
 */
export const validateReference = (reference) => {
  if (!reference || typeof reference !== 'string') {
    return false;
  }
  // Pattern: ^[0-9a-zA-Z \w+]{1,20}$
  // In JavaScript: alphanumeric, space, word characters (includes underscore), plus sign, 1-20 chars
  const referencePattern = /^[0-9a-zA-Z _+]{1,20}$/;
  return referencePattern.test(reference.trim());
};

/**
 * Generate reference number for disbursement
 * Pattern must match: ^[0-9a-zA-Z _+]{1,20}$
 * @param {string} provider - Provider name
 * @returns {string} Generated reference (max 20 chars, alphanumeric, space, underscore, plus only)
 */
export const generateReference = (provider) => {
  const safeProvider = (provider || 'MOMO').toUpperCase().replace(/[^0-9A-Z]/g, '').substring(0, 3);
  const timestamp = Date.now().toString().slice(-8); // Last 8 digits of timestamp
  const randomSegment = Math.floor(Math.random() * 10000)
    .toString()
    .padStart(4, '0');
  // Format: PREFIX + timestamp + random (max 20 chars)
  // Example: MTN12345678901234 (16 chars) or TEL123456789012345 (17 chars)
  const reference = `${safeProvider}${timestamp}${randomSegment}`.substring(0, 20);
  return reference;
};

/**
 * Extract account name from API response
 * @param {object} response - API response object
 * @returns {string|null} Account name or null
 */
export const extractAccountName = (response) => {
  return (
    response?.data?.accountname ||
    response?.data?.accountName ||
    response?.accountname ||
    response?.accountName ||
    null
  );
};

/**
 * Parse account name into firstName and surname
 * @param {string} accountName - Full account name
 * @returns {{firstName: string, surname: string}} Parsed name parts
 */
export const parseAccountName = (accountName) => {
  if (!accountName) {
    return { firstName: '', surname: '' };
  }
  
  const nameParts = accountName.trim().split(/\s+/).filter(part => part.length > 0);
  const firstName = nameParts.shift() || '';
  const surname = nameParts.join(' ') || '';
  
  return { firstName, surname };
};

/**
 * Check if API response indicates success
 * @param {object} response - API response object
 * @returns {boolean} True if successful
 */
export const isSuccessResponse = (response) => {
  return (
    response?.code === '00' ||
    response?.data?.status === 'SUCCESS' ||
    (response?.status || '').toString().toUpperCase() === 'SUCCESS'
  );
};

